+#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
+pub struct CleanupDiagnostics {
+    pub backend_name: String,
+    pub model_name: String,
+    #[serde(default, skip_serializing_if = "Option::is_none")]
+    pub cleaned_text: Option<String>,
+    pub elapsed_ms: u64,
+    pub used_ocr: bool,
+    pub succeeded: bool,
+    #[serde(default, skip_serializing_if = "Option::is_none")]
+    pub failure_reason: Option<String>,
+}
+
+impl CleanupDiagnostics {
+    pub fn succeeded(
+        backend_name: impl Into<String>,
+        model_name: impl Into<String>,
+        cleaned_text: impl Into<String>,
+        elapsed: Duration,
+    ) -> Self {
+        Self {
+            backend_name: backend_name.into(),
+            model_name: model_name.into(),
+            cleaned_text: Some(cleaned_text.into()),
+            elapsed_ms: elapsed.as_millis() as u64,
+            used_ocr: false,
+            succeeded: true,
+            failure_reason: None,
+        }
+    }
+
+    pub fn failed(
+        backend_name: impl Into<String>,
+        model_name: impl Into<String>,
+        failure_reason: impl Into<String>,
+    ) -> Self {
+        Self {
+            backend_name: backend_name.into(),
+            model_name: model_name.into(),
+            cleaned_text: None,
+            elapsed_ms: 0,
+            used_ocr: false,
+            succeeded: false,
+            failure_reason: Some(failure_reason.into()),
+        }
+    }
+
+    pub fn cleaned_text(&self) -> Option<&str> {
+        self.cleaned_text.as_deref().filter(|_| self.succeeded)
+    }
 }

